SET standard_conforming_strings = OFF;
DROP TABLE IF EXISTS "public"."roads" CASCADE;
DELETE FROM geometry_columns WHERE f_table_name = 'roads' AND f_table_schema = 'public';
BEGIN;
CREATE TABLE "public"."roads" ( "ogc_fid" SERIAL, CONSTRAINT "roads_pk" PRIMARY KEY ("ogc_fid") );
SELECT AddGeometryColumn('public','roads','wkb_geometry',2178,'MULTIPOLYGON',2);
CREATE INDEX "roads_wkb_geometry_geom_idx" ON "public"."roads" USING GIST ("wkb_geometry");
ALTER TABLE "public"."roads" ADD COLUMN "objectid" NUMERIC(10,0);
ALTER TABLE "public"."roads" ADD COLUMN "fid_road" NUMERIC(10,0);
ALTER TABLE "public"."roads" ADD COLUMN "absorptive" NUMERIC(19,11);
ALTER TABLE "public"."roads" ADD COLUMN "area" NUMERIC(19,11);
ALTER TABLE "public"."roads" ADD COLUMN "surftype" VARCHAR(50);
ALTER TABLE "public"."roads" ADD COLUMN "local_" VARCHAR(3);
ALTER TABLE "public"."roads" ADD COLUMN "active" NUMERIC(10,0);
ALTER TABLE "public"."roads" ADD COLUMN "shape_leng" NUMERIC(19,11);
ALTER TABLE "public"."roads" ADD COLUMN "shape_area" NUMERIC(19,11);
COMMIT;
